import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

public class XMLTokenerTest {

    @Test
    public void nextCDATA_ReturnsCorrectString_WhenCDATAIsWellFormed() {
        XMLTokener xmlTokener = new XMLTokener("<![CDATA[This is some CDATA]]>");
        String result = xmlTokener.nextCDATA();
        assertEquals("This is some CDATA", result);
    }

    @Test
    public void nextCDATA_ThrowsException_WhenCDATAIsNotClosed() {
        XMLTokener xmlTokener = new XMLTokener("<![CDATA[This is some CDATA");
        assertThrows(JSONException.class, xmlTokener::nextCDATA);
    }

    @Test
    public void nextCDATA_ReturnsEmptyString_WhenCDATAIsEmpty() {
        XMLTokener xmlTokener = new XMLTokener("<![CDATA[]]>");
        String result = xmlTokener.nextCDATA();
        assertEquals("", result);
    }

    @Test
    public void nextCDATA_ThrowsException_WhenCDATAIsNotProperlyFormed() {
        XMLTokener xmlTokener = new XMLTokener("<![This is some CDATA]]>");
        assertThrows(JSONException.class, xmlTokener::nextCDATA);
    }
}

import org.activiti.engine.impl.util.io.InputStreamSource;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;

import static org.junit.jupiter.api.Assertions.*;

public class InputStreamSourceTest {

    @Test
    public void getBytesFromInputStream_readsAllBytes() throws IOException {
        InputStreamSource source = new InputStreamSource(new ByteArrayInputStream(new byte[]{1, 2, 3}));
        byte[] bytes = source.getBytesFromInputStream(new ByteArrayInputStream(new byte[]{1, 2, 3}));
        assertArrayEquals(new byte[]{1, 2, 3}, bytes);
    }

    @Test
    public void getBytesFromInputStream_emptyStream_returnsEmptyArray() throws IOException {
        InputStreamSource source = new InputStreamSource(new ByteArrayInputStream(new byte[]{}));
        byte[] bytes = source.getBytesFromInputStream(new ByteArrayInputStream(new byte[]{}));
        assertArrayEquals(new byte[]{}, bytes);
    }

    @Test
    public void getBytesFromInputStream_largeStream_readsAllBytes() throws IOException {
        byte[] largeArray = new byte[10000];
        for (int i = 0; i < largeArray.length; i++) {
            largeArray[i] = (byte) i;
        }
        InputStreamSource source = new InputStreamSource(new ByteArrayInputStream(largeArray));
        byte[] bytes = source.getBytesFromInputStream(new ByteArrayInputStream(largeArray));
        assertArrayEquals(largeArray, bytes);
    }

    @Test
    public void getBytesFromInputStream_streamThrowsException_propagatesException() {
        InputStream stream = new InputStream() {
            @Override
            public int read() throws IOException {
                throw new IOException("Test exception");
            }
        };
        InputStreamSource source = new InputStreamSource(stream);
        assertThrows(IOException.class, () -> source.getBytesFromInputStream(stream));
    }
}

