    private ProcessDefinitionInfoEntity processDefinitionInfoEntity;

    private ProcessDefinitionInfoCache processDefinitionInfoCache;

    @BeforeEach
    public void setUp() {
        MockitoAnnotations.openMocks(this);
        processDefinitionInfoCache = new ProcessDefinitionInfoCache(commandExecutor);
    }

    @Test
    public void getReturnsCachedObjectWhenPresent() {
        String processDefinitionId = "testId";
        ProcessDefinitionInfoCacheObject cachedObject = new ProcessDefinitionInfoCacheObject();
        processDefinitionInfoCache.add(processDefinitionId, cachedObject);

        ProcessDefinitionInfoCacheObject result = processDefinitionInfoCache.get(processDefinitionId);

        assertEquals(cachedObject, result);
    }

    @Test
    public void getReturnsNewObjectWhenNotPresent() {
        String processDefinitionId = "testId";

        when(commandExecutor.execute(any())).thenReturn(new ProcessDefinitionInfoCacheObject());

        ProcessDefinitionInfoCacheObject result = processDefinitionInfoCache.get(processDefinitionId);

        assertNotNull(result);
        assertEquals(0, result.getRevision());
    }

