import org.activiti.engine.impl.cfg.TransactionContext;
import org.activiti.engine.impl.context.Context;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import static org.mockito.Mockito.*;

class TransactionContextInterceptorTest {

    @Mock
    private TransactionContextFactory transactionContextFactory;

    @Mock
    private CommandConfig commandConfig;

    @Mock
    private Command command;

    @Mock
    private CommandContext commandContext;

    @Mock
    private TransactionContext transactionContext;

    private TransactionContextInterceptor transactionContextInterceptor;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        transactionContextInterceptor = new TransactionContextInterceptor(transactionContextFactory);
        when(Context.getCommandContext()).thenReturn(commandContext);
    }

    @Test
    void execute_createsTransactionContext_whenCommandContextIsNotReused() {
        when(commandContext.isReused()).thenReturn(false);
        when(transactionContextFactory.openTransactionContext(commandContext)).thenReturn(transactionContext);

        transactionContextInterceptor.execute(commandConfig, command);

        verify(transactionContextFactory).openTransactionContext(commandContext);
        verify(commandContext).addCloseListener(any(TransactionCommandContextCloseListener.class));
    }

    @Test
    void execute_doesNotCreateTransactionContext_whenCommandContextIsReused() {
        when(commandContext.isReused()).thenReturn(true);

        transactionContextInterceptor.execute(commandConfig, command);

        verify(transactionContextFactory, never()).openTransactionContext(commandContext);
        verify(commandContext, never()).addCloseListener(any(TransactionCommandContextCloseListener.class));
    }

    @Test
    void execute_removesTransactionContext_whenCommandContextIsNotReused() {
        when(commandContext.isReused()).thenReturn(false);
        when(transactionContextFactory.openTransactionContext(commandContext)).thenReturn(transactionContext);

        transactionContextInterceptor.execute(commandConfig, command);

        verify(Context).removeTransactionContext();
    }

    @Test
    void execute_doesNotRemoveTransactionContext_whenCommandContextIsReused() {
        when(commandContext.isReused()).thenReturn(true);

        transactionContextInterceptor.execute(commandConfig, command);

        verify(Context, never()).removeTransactionContext();
    }
}

