    public void setUp() {
        historicVariableInstanceEntity = new HistoricVariableInstanceEntityImpl();
        mockVariableType = mock(VariableType.class);
        historicVariableInstanceEntity.setVariableType(mockVariableType);
    }

    @Test
    public void getPersistentState_shouldReturnMapWithCorrectValues_whenCalled() {
        historicVariableInstanceEntity.setTextValue("textValue");
        historicVariableInstanceEntity.setTextValue2("textValue2");
        historicVariableInstanceEntity.setDoubleValue(1.0);
        historicVariableInstanceEntity.setLongValue(1L);

        assertThat(historicVariableInstanceEntity.getPersistentState()).containsEntry("textValue", "textValue")
                .containsEntry("textValue2", "textValue2").containsEntry("doubleValue", 1.0)
                .containsEntry("longValue", 1L);
