    public void getValue_shouldReturnCachedValue_whenVariableTypeIsCachableAndCachedValueIsNotNull() {
        when(mockVariableType.isCachable()).thenReturn(true);
        historicVariableInstanceEntity.setCachedValue("cachedValue");

        assertThat(historicVariableInstanceEntity.getValue()).isEqualTo("cachedValue");
