        when(mockVariableType.isCachable()).thenReturn(true);
        when(mockVariableType.getValue(historicVariableInstanceEntity)).thenReturn("variableTypeValue");

        assertThat(historicVariableInstanceEntity.getValue()).isEqualTo("variableTypeValue");
    }
}

