public class ProcessEngineConfigurationImplTest {

    private ProcessEngineConfigurationImpl processEngineConfiguration;
    private BpmnParser bpmnParser;
    private BpmnParseFactory bpmnParseFactory;

    @BeforeEach
    public void setUp() {
        processEngineConfiguration = new ProcessEngineConfigurationImpl();
        bpmnParser = Mockito.mock(BpmnParser.class);
        bpmnParseFactory = Mockito.mock(BpmnParseFactory.class);
    }

    @Test
    public void shouldInitBpmnParserWhenBpmnParserIsNull() {
        processEngineConfiguration.initBpmnParser();

        assertNotNull(processEngineConfiguration.getBpmnParser());
    }

    @Test
    public void shouldNotInitBpmnParserWhenBpmnParserIsNotNull() {
        processEngineConfiguration.setBpmnParser(bpmnParser);

        processEngineConfiguration.initBpmnParser();

        assertSame(bpmnParser, processEngineConfiguration.getBpmnParser());
    }

    @Test
    public void shouldSetBpmnParseFactoryWhenBpmnParseFactoryIsNull() {
        processEngineConfiguration.setBpmnParser(bpmnParser);

        processEngineConfiguration.initBpmnParser();

        verify(bpmnParser).setBpmnParseFactory(Mockito.any(BpmnParseFactory.class));
    }

    @Test
    public void shouldNotSetBpmnParseFactoryWhenBpmnParseFactoryIsNotNull() {
        processEngineConfiguration.setBpmnParser(bpmnParser);
        processEngineConfiguration.setBpmnParseFactory(bpmnParseFactory);

        processEngineConfiguration.initBpmnParser();

        verify(bpmnParser, Mockito.never()).setBpmnParseFactory(Mockito.any(BpmnParseFactory.class));
    }
